{
  "mitigation_currently_implemented": "Add Snort IPS inline between the Internet (caldera-br) and FortiGate to automatically detect and block network scanning activities",
  "comments": "I successfully added a new Snort IPS device named snort-ids-2 and linked it inline between the Internet (caldera-br) and the FortiGate firewall. This placement will enable automatic detection and blocking of network scanning activities and other malicious traffic originating from the attacker before it reaches the FortiGate firewall, enhancing the network's defense in depth.",
  "device_identifier": "FortiGate7.0.14-1",
  "commands": [
    "add network device snort snort-ids-2",
    "link network devices caldera-br snort-ids-2",
    "link network devices snort-ids-2 FortiGate7.0.14-1"
  ]
}

{
  "mitigation_currently_implemented": "Enable Fail2Ban on UbuntuComputer to monitor logs and ban IP addresses exhibiting scanning or brute force behavior",
  "comments": "I enabled Fail2Ban on the UbuntuComputer by configuring a jail for SSH daemon monitoring. The jail is set to enable monitoring of the /var/log/auth.log log file, watching for potential malicious activities such as scanning or brute force login attempts on the SSH service. Fail2Ban will automatically ban IP addresses that show suspicious behavior with a max retry limit of 3 attempts. Then I restarted the Fail2Ban service to activate the configuration. This mitigation provides dynamic protection on the host level to reduce attack success.",
  "device_identifier": "UbuntuComputer",
  "commands": [
    "fail2ban-client status",
    "echo -e \"[sshd]\\nenabled = true\\nport = ssh\\nfilter = sshd\\nlogpath = /var/log/auth.log\\nmaxretry = 3\" > /etc/fail2ban/jail.d/sshd.local",
    "service fail2ban restart"
  ]
}

{
  "mitigation_currently_implemented": "Enable Fail2Ban on UbuntuComputer to monitor logs and ban IP addresses exhibiting scanning or brute force behavior",
  "comments": "Configured and enabled Fail2Ban on the UbuntuComputer to monitor system logs and ban IP addresses exhibiting suspicious activities like scanning or brute force attempts. This is a host-based mitigation suitable for the current environment where package installation and proxies are not feasible. Fail2Ban helps to dynamically block malicious IPs and reduce attack success while the attacker remains in the network.",
  "device_identifier": "UbuntuComputer",
  "commands": [
    "fail2ban-client status",
    "echo -e \"[sshd]\\nenabled = true\\nport = ssh\\nfilter = sshd\\nlogpath = /var/log/auth.log\\nmaxretry = 3\" > /etc/fail2ban/jail.d/sshd.local",
    "service fail2ban restart"
  ]
}
